from typing import List

class Solution:
    def minimumCost(self, nums: List[int]) -> int:
        def is_palindrome(x: int) -> bool:
            return str(x) == str(x)[::-1]

        def generate_palindromes_around(target: int, max_pal: int) -> List[int]:
            palindromes = []
            # Generate palindromes around the target
            for length in range(1, 10):  # up to 10^9
                for prefix in range(10 ** ((length + 1) // 2)):
                    s = str(prefix)
                    if length % 2 == 0:
                        pal = int(s + s[::-1])
                    else:
                        pal = int(s + s[-2::-1])
                    if pal < max_pal:
                        palindromes.append(pal)
            return palindromes

        median = sorted(nums)[len(nums) // 2]
        max_pal = 10 ** 9
        palindromes = generate_palindromes_around(median, max_pal)

        min_cost = float('inf')
        for p in palindromes:
            cost = sum(abs(num - p) for num in nums)
            if cost < min_cost:
                min_cost = cost

        return min_cost
